FINAL_ANSWER: import sys

def solve():
    input_data = sys.stdin.read().split()
    if not input_data: return
    N, M, K = map(int, input_data[:3])
    idx = 3
    board = []
    for _ in range(N):
        board.append(list(map(int, input_data[idx:idx+N])))
        idx += N
    stamps = []
    for _ in range(M):
        stamp = []
        for _ in range(3):
            stamp.append(list(map(int, input_data[idx:idx+3])))
            idx += 3
        stamps.append(stamp)

    placements = []
    current_board = [row[:] for row in board]

    for m_idx, stamp in enumerate(stamps):
        best_score = -1
        best_pos = None
        for r in range(N - 2):
            for c in range(N - 2):
                score = 0
                for dr in range(3):
                    for dc in range(3):
                        if stamp[dr][dc] == 1 and current_board[r+dr][c+dc] == 0:
                            score += 1
                if score > best_score:
                    best_score = score
                    best_pos = (r, c)

        if best_pos and best_score > 0:
            r, c = best_pos
            placements.append((m_idx, r, c))
            for dr in range(3):
                for dc in range(3):
                    if stamp[dr][dc] == 1:
                        current_board[r+dr][c+dc] = 1

    print(len(placements))
    for p in placements:
        print(f"{p[0]} {p[1]} {p[2]}")

if __name__ == "__main__":
    solve()

